const apolloData = $('Enrich via Apollo API').first().json;
const clearbitData = $('Clearbit Company Lookup').first().json;
const originalLead = $('Webhook: New Lead').first().json;

const enriched = {
  ...originalLead,

  // Apollo enrichment
  decision_makers: apolloData.people ? apolloData.people.slice(0, 5).map(p => ({
    name: p.name,
    title: p.title,
    email: p.email,
    linkedin: p.linkedin_url
  })) : [],

  // Clearbit enrichment
  tech_stack: clearbitData.tech || [],
  funding_total: clearbitData.metrics?.raised || 'Unknown',
  annual_revenue: clearbitData.metrics?.annualRevenue || 'Unknown',
  company_type: clearbitData.type || 'Unknown',
  twitter_followers: clearbitData.twitter?.followers || 0,

  // Enrichment metadata
  enriched_at: new Date().toISOString(),
  enrichment_sources: ['apollo', 'clearbit'],
  enrichment_status: 'completed'
};

return [{ json: enriched }];

