const enrichedLead = $('Merge Enrichment Data').first().json;
const aiResponse = $input.first().json;

let aiAnalysis;
try {
  const content = aiResponse.content[0].text;
  aiAnalysis = JSON.parse(content);
} catch (e) {
  aiAnalysis = {
    score: 50,
    action: 'manual_review',
    insights: 'AI analysis parsing failed - manual review needed'
  };
}

const finalLead = {
  ...enrichedLead,
  ai_score: aiAnalysis.score || 50,
  ai_recommended_action: aiAnalysis.action || 'review',
  ai_insights: aiAnalysis.insights || '',
  ai_buying_signals: aiAnalysis.buying_signals || [],
  ai_risk_factors: aiAnalysis.risk_factors || [],

  // Final composite score (weighted)
  final_score: Math.round(
    (enrichedLead.lead_score * 0.4) + (aiAnalysis.score * 0.6)
  ),

  // Final tier
  final_tier: '',
  processed_at: new Date().toISOString()
};

finalLead.final_tier = finalLead.final_score >= 75 ? 'high_priority' 
  : finalLead.final_score >= 50 ? 'medium_priority' 
  : 'low_priority';

return [{ json: finalLead }];

